sql:
SELECT experiment_id, COUNT(*) AS total_comments
FROM experiment_comments
GROUP BY experiment_id;

external_knowledge:
- 'ongoing' refers to experiments with an 'active' status;
- 'non-administrative staff' implies users whose role is not 'admin';
- 'quite some time' is defined as more than 30 days;
- 'haven't been touched' can mean either there are no recorded access logs or the last access date is over 30 days ago.

sql:
SELECT e.experiment_name, ec.comment_text
FROM experiments e
LEFT JOIN experiment_comments ec ON e.experiment_id = ec.experiment_id;

SELECT DISTINCT experiment_name 
FROM experiments 
WHERE experiment_type_id = 3;

SELECT users.user_name, users.email, roles.role_name
FROM users
LEFT JOIN roles ON users.role_id = roles.role_id;

external_knowledge:
- 'explorers' refers to 'users';
- 'crew roles' refers to 'user roles';
- 'latest voyages' refer to the experiments accessed by users;
- 'within the horizon of the last 30 days' means the access date is within the last 30 days from today.

sql:
SELECT e.experiment_name, et.experiment_type_name
FROM experiments e
JOIN experiment_types et ON e.experiment_type_id = et.experiment_type_id;

external_knowledge:
- 'gardeners' refers to the users who created the experiments;
- 'seeds of active experiments' refers to active experiments;
- 'blossoms' represents the data points associated with each experiment.

